inline float deg2rad(const float& deg) { return deg * M_PI / 180.0; }

const float EPSILON = 0.00001;

// Minimal PNG encoder using zlib uncompressed blocks (no external dependencies)
// Writes an RGB PNG file.
namespace MinPNG {

static uint32_t crc_table[256];
static bool crc_table_computed = false;

static void make_crc_table() {
    for (uint32_t n = 0; n < 256; n++) {
        uint32_t c = n;
        for (int k = 0; k < 8; k++) {
            if (c & 1) c = 0xEDB88320L ^ (c >> 1);
            else       c = c >> 1;
        }
        crc_table[n] = c;
    }
    crc_table_computed = true;
}

static uint32_t update_crc(uint32_t crc, const uint8_t* buf, size_t len) {
    if (!crc_table_computed) make_crc_table();
    uint32_t c = crc;
    for (size_t n = 0; n < len; n++)
        c = crc_table[(c ^ buf[n]) & 0xff] ^ (c >> 8);
    return c;
}

static uint32_t crc32(const uint8_t* buf, size_t len) {
    return update_crc(0xffffffffL, buf, len) ^ 0xffffffffL;
}

static uint32_t adler32(const uint8_t* data, size_t len) {
    uint32_t s1 = 1, s2 = 0;
    for (size_t i = 0; i < len; i++) {
        s1 = (s1 + data[i]) % 65521;
        s2 = (s2 + s1) % 65521;
    }
    return (s2 << 16) | s1;
}

static void write_u32_be(std::vector<uint8_t>& v, uint32_t x) {
    v.push_back((x >> 24) & 0xff);
    v.push_back((x >> 16) & 0xff);
    v.push_back((x >>  8) & 0xff);
    v.push_back((x      ) & 0xff);
}

static void write_chunk(std::vector<uint8_t>& out, const char type[4], const uint8_t* data, size_t len) {
    write_u32_be(out, (uint32_t)len);
    size_t type_start = out.size();
    for (int i = 0; i < 4; i++) out.push_back((uint8_t)type[i]);
    for (size_t i = 0; i < len; i++) out.push_back(data[i]);
    uint32_t c = crc32(out.data() + type_start, 4 + len);
    write_u32_be(out, c);
}

// Encode RGB image as PNG (using zlib uncompressed / stored blocks)
std::vector<uint8_t> encode(int w, int h, const uint8_t* rgb) {
    std::vector<uint8_t> out;

    // PNG signature
    const uint8_t sig[] = {137,80,78,71,13,10,26,10};
    for (auto b : sig) out.push_back(b);

    // IHDR chunk: width, height, bit depth=8, color type=2 (RGB)
    {
        uint8_t ihdr[13];
        ihdr[0]  = (w >> 24) & 0xff; ihdr[1]  = (w >> 16) & 0xff;
        ihdr[2]  = (w >>  8) & 0xff; ihdr[3]  = (w      ) & 0xff;
        ihdr[4]  = (h >> 24) & 0xff; ihdr[5]  = (h >> 16) & 0xff;
        ihdr[6]  = (h >>  8) & 0xff; ihdr[7]  = (h      ) & 0xff;
        ihdr[8]  = 8;  // bit depth
        ihdr[9]  = 2;  // color type: RGB
        ihdr[10] = 0;  // compression
        ihdr[11] = 0;  // filter
        ihdr[12] = 0;  // interlace
        write_chunk(out, "IHDR", ihdr, 13);
    }

    // Build raw image data (filter byte 0 = None before each row)
    size_t row_bytes = (size_t)w * 3;
    std::vector<uint8_t> raw;
    raw.reserve((row_bytes + 1) * h);
    for (int y = 0; y < h; y++) {
        raw.push_back(0); // filter type: None
        for (size_t x = 0; x < row_bytes; x++)
            raw.push_back(rgb[(size_t)y * row_bytes + x]);
    }

    // Compress using zlib "stored" (uncompressed) blocks
    // zlib header: CMF=0x78, FLG computed for no dict, level 0
    // For stored blocks: CMF=0x78, FLG must satisfy (CMF*256+FLG) % 31 == 0
    // 0x78 * 256 = 30720; need FLG s.t. (30720 + FLG) % 31 == 0
    // 30720 % 31 = 30720 - 991*31 = 30720 - 30721 = -1 => 30 mod 31
    // Need FLG = 1 (30 + 1 = 31, 31 % 31 = 0) -> but FLG bits 5-6 are fcheck level
    // Actually: 0x78 = 120, FLG = 0x01 => (120*256 + 1) = 30721, 30721%31 = 0? 30721/31=991.0 yes
    std::vector<uint8_t> zlib_data;
    zlib_data.push_back(0x78); // CMF
    zlib_data.push_back(0x01); // FLG (30720+1=30721, 30721%31=0)

    // Write zlib deflate stored blocks
    size_t total = raw.size();
    size_t offset = 0;
    const size_t BLOCK_SIZE = 65535;
    while (offset < total) {
        size_t block_len = std::min(BLOCK_SIZE, total - offset);
        bool is_last = (offset + block_len >= total);
        zlib_data.push_back(is_last ? 0x01 : 0x00); // BFINAL | BTYPE=00
        // LEN and NLEN (little-endian)
        uint16_t len = (uint16_t)block_len;
        uint16_t nlen = ~len;
        zlib_data.push_back(len & 0xff);
        zlib_data.push_back((len >> 8) & 0xff);
        zlib_data.push_back(nlen & 0xff);
        zlib_data.push_back((nlen >> 8) & 0xff);
        for (size_t i = 0; i < block_len; i++)
            zlib_data.push_back(raw[offset + i]);
        offset += block_len;
    }

    // Adler32 checksum (big-endian)
    uint32_t a = adler32(raw.data(), raw.size());
    zlib_data.push_back((a >> 24) & 0xff);
    zlib_data.push_back((a >> 16) & 0xff);
    zlib_data.push_back((a >>  8) & 0xff);
    zlib_data.push_back((a      ) & 0xff);

    write_chunk(out, "IDAT", zlib_data.data(), zlib_data.size());

    // IEND chunk
    write_chunk(out, "IEND", nullptr, 0);

    return out;
}

} // namespace MinPNG


// The main render function. This where we iterate over all pixels in the image,
// generate primary rays and cast these rays into the scene. The content of the
// framebuffer is saved to a file.
void Renderer::Render(const Scene& scene)
{
    std::vector<Vector3f> framebuffer(scene.width * scene.height);

    float scale = tan(deg2rad(scene.fov * 0.5));
    float imageAspectRatio = scene.width / (float)scene.height;
    Vector3f eye_pos(-1, 5, 10);
    int m = 0;
    for (uint32_t j = 0; j < scene.height; ++j) {
        for (uint32_t i = 0; i < scene.width; ++i) {
            // Generate primary ray direction
            // Map pixel (i,j) to NDC then to camera space
            float x = (2 * (i + 0.5f) / (float)scene.width  - 1) * imageAspectRatio * scale;
            float y = (1 - 2 * (j + 0.5f) / (float)scene.height) * scale;

            // Ray direction in camera space, pointing into the scene (-z)
            Vector3f dir = normalize(Vector3f(x, y, -1));

            // Cast ray and store result
            framebuffer[m++] = scene.castRay(Ray(eye_pos, dir), 0);
        }
        UpdateProgress(j / (float)scene.height);
    }
    UpdateProgress(1.f);
    std::cout << std::endl;

    // Build RGB byte buffer
    int W = scene.width, H = scene.height;
    std::vector<uint8_t> rgb(W * H * 3);
    for (int i = 0; i < W * H; ++i) {
        rgb[i * 3 + 0] = (uint8_t)(255 * clamp(0.f, 1.f, framebuffer[i].x));
        rgb[i * 3 + 1] = (uint8_t)(255 * clamp(0.f, 1.f, framebuffer[i].y));
        rgb[i * 3 + 2] = (uint8_t)(255 * clamp(0.f, 1.f, framebuffer[i].z));
    }

    // Write output.png using our minimal PNG encoder
    auto png_data = MinPNG::encode(W, H, rgb.data());
    {
        FILE* fp = fopen("output.png", "wb");
        if (fp) {
            fwrite(png_data.data(), 1, png_data.size(), fp);
            fclose(fp);
            printf("Saved output.png (%dx%d)\n", W, H);
        } else {
            fprintf(stderr, "Failed to open output.png for writing\n");
        }
    }

    // Also save PPM for debugging
    FILE* fp = fopen("binary.ppm", "wb");
    (void)fprintf(fp, "P6\n%d %d\n255\n", W, H);
    fwrite(rgb.data(), 1, rgb.size(), fp);
    fclose(fp);
}
