inline bool Bounds3::IntersectP(const Ray& ray, const Vector3f& invDir,
                                const std::array<int, 3>& dirIsNeg) const
{
    // invDir: ray direction(x,y,z), invDir=(1.0/x,1.0/y,1.0/z), use this because Multiply is faster that Division
    // dirIsNeg: ray direction(x,y,z), dirIsNeg=[int(x<0),int(y<0),int(z<0)], use this to simplify your logic

    // For each axis, compute tMin and tMax for the slab
    // Use dirIsNeg to select the correct min/max bound

    float tMin_x = ((*this)[dirIsNeg[0]].x - ray.origin.x) * invDir.x;
    float tMax_x = ((*this)[1 - dirIsNeg[0]].x - ray.origin.x) * invDir.x;

    float tMin_y = ((*this)[dirIsNeg[1]].y - ray.origin.y) * invDir.y;
    float tMax_y = ((*this)[1 - dirIsNeg[1]].y - ray.origin.y) * invDir.y;

    float tMin_z = ((*this)[dirIsNeg[2]].z - ray.origin.z) * invDir.z;
    float tMax_z = ((*this)[1 - dirIsNeg[2]].z - ray.origin.z) * invDir.z;

    float tEnter = std::max({tMin_x, tMin_y, tMin_z});
    float tExit  = std::min({tMax_x, tMax_y, tMax_z});

    return tEnter <= tExit && tExit >= 0;
}

inline Bounds3 Union(const Bounds3& b1, const Bounds3& b2)
{
    Bounds3 ret;
    ret.pMin = Vector3f::Min(b1.pMin, b2.pMin);
    ret.pMax = Vector3f::Max(b1.pMax, b2.pMax);
    return ret;
}

inline Bounds3 Union(const Bounds3& b, const Vector3f& p)
{
    Bounds3 ret;
    ret.pMin = Vector3f::Min(b.pMin, p);
    ret.pMax = Vector3f::Max(b.pMax, p);
    return ret;
}

#endif // RAYTRACING_BOUNDS3_H
