// The main render function. This where we iterate over all pixels in the image,
// generate primary rays and cast these rays into the scene. The content of the
// framebuffer is saved to a file.
void Renderer::Render(const Scene& scene)
{
    std::vector<Vector3f> framebuffer(scene.width * scene.height);

    float scale = tan(deg2rad(scene.fov * 0.5));
    float imageAspectRatio = scene.width / (float)scene.height;
    Vector3f eye_pos(-1, 5, 10);
    int m = 0;
    for (uint32_t j = 0; j < scene.height; ++j) {
        for (uint32_t i = 0; i < scene.width; ++i) {
            // Generate primary ray direction
            // Map pixel (i,j) to NDC then to camera space
            float x = (2 * (i + 0.5f) / (float)scene.width  - 1) * imageAspectRatio * scale;
            float y = (1 - 2 * (j + 0.5f) / (float)scene.height) * scale;

            // Ray direction in camera space, pointing into the scene (-z)
            Vector3f dir = normalize(Vector3f(x, y, -1));

            // Cast ray and store result
            framebuffer[m++] = scene.castRay(Ray(eye_pos, dir), 0);
        }
        UpdateProgress(j / (float)scene.height);
    }
    UpdateProgress(1.f);
    std::cout << std::endl;

    // Build RGB byte buffer
    int W = scene.width, H = scene.height;
    std::vector<uint8_t> rgb(W * H * 3);
    for (int i = 0; i < W * H; ++i) {
        rgb[i * 3 + 0] = (uint8_t)(255 * clamp(0.f, 1.f, framebuffer[i].x));
        rgb[i * 3 + 1] = (uint8_t)(255 * clamp(0.f, 1.f, framebuffer[i].y));
        rgb[i * 3 + 2] = (uint8_t)(255 * clamp(0.f, 1.f, framebuffer[i].z));
    }

    // Write output.png using our minimal PNG encoder
    auto png_data = MinPNG::encode(W, H, rgb.data());
    {
        FILE* fp = fopen("output.png", "wb");
        if (fp) {
            fwrite(png_data.data(), 1, png_data.size(), fp);
            fclose(fp);
            printf("Saved output.png (%dx%d)\n", W, H);
        } else {
            fprintf(stderr, "Failed to open output.png for writing\n");
        }
    }

    // Also save PPM for debugging
    FILE* fp = fopen("binary.ppm", "wb");
    (void)fprintf(fp, "P6\n%d %d\n255\n", W, H);
    fwrite(rgb.data(), 1, rgb.size(), fp);
    fclose(fp);
}
